var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"흑, 흐윽……!","JPN":"うっ、ううっ……！","ENG":"*Sob* *Sniffle*","TWN":"嗚嗚，嗚嗚……！"},"stage":{"bg":"SWANSONG_04","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"죄송해요, 죄송해요……! 저 때문에 당신이……!","JPN":"ごめんなさ、うっ、ごめんなさい……！　私のせいであなたが……！","ENG":"I'm sorry, I'm sorry...! Because of me, you...!","TWN":"對不起，對不起……！因為我害得你……！"},"stage":{"bg":"SWANSONG_04","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"당신은……. 저를 지켜주려다가……!","JPN":"あなたは……私を庇おうとして……！","ENG":"While... trying to protect me...!","TWN":"為了保護我……！"},"stage":{"bg":"SWANSONG_04","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"여기는……?","JPN":"ここは……？","ENG":"What is this place?","TWN":"這裡是……？"},"stage":{"bg":"SWANSONG_04","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"애, 애버라인! 정신이 드세요?","JPN":"あ、アバーライン！　気がつきました？","ENG":"A-Abberline! Are you okay?","TWN":"艾，艾伯林！你醒了嗎？"},"stage":{"bg":"SWANSONG_04","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L8_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇군……. 마물의 공격을 피해, 숲 속에 있던 폭포 아래로 떨어지고 말았나……?","JPN":"そうか……魔物から逃げようとして、森の中にあった滝の下に落ちてしまったのか……？","ENG":"I see... So we fell down the waterfall in the forest while trying to avoid the monster's attack...","TWN":"原來如此……為了躲避怪物的攻擊，掉到了森林裡的瀑布下嗎……？"},"stage":{"bg":"SWANSONG_04","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다면 자네가 나를 감싸서……","JPN":"ということは、君が私を庇って……","ENG":"Then you protected me–","TWN":"那麼是你救了我……"},"stage":{"bg":"SWANSONG_04","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"크윽!","JPN":"うっ！","ENG":"Urgh!","TWN":"咳！"},"stage":{"bg":"SWANSONG_04","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"애버라인, 그만 말해요! 피가, 피가 많이 난다고요……!","JPN":"しゃ、喋っちゃダメ、アバーライン！　血が、出血がひどい……！","ENG":"Abberline, stop talking! You're... you're bleeding a lot...!","TWN":"艾伯林，別說了！血，血流得很多啊……！"},"stage":{"bg":"SWANSONG_04","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"다행이야……. 덕분에 약간이나마 시간을 벌었군…….","JPN":"よかった……おかげで少しは時間を稼げたか。","ENG":"Thank goodness... We bought some time thanks to you...","TWN":"太好了……多虧如此，總算爭取到了一點時間……"},"stage":{"bg":"SWANSONG_04","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 역시 내 눈은 틀리지 않았어…….","JPN":"ふふ、やはり私の目に狂いはなかったようだ……","ENG":"Haha, I knew my eyes are never wrong...","TWN":"呵呵，果然我的眼睛沒有看錯……"},"stage":{"bg":"SWANSONG_04","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네는 내 훌륭한 파트너야.","JPN":"君は私の立派なパートナーだ。","ENG":"You're a great partner.","TWN":"你是我出色的搭檔。"},"stage":{"bg":"SWANSONG_04","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"제발! 왜 이런 상황에까지 웃는 건데요!","JPN":"やめてください！　どうしてこんな状況にまで笑ってるんですか！","ENG":"Come on! How are you laughing at this situation?!","TWN":"拜託！為什麼這種情況下你還在笑！"},"stage":{"bg":"SWANSONG_04","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L18_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"나는, 나는……!","JPN":"私、私は……！","ENG":"I... I...!","TWN":"我，我……！"},"stage":{"bg":"SWANSONG_04","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"애버라인, 당신이……!","JPN":"アバーライン、あなたが……！","ENG":"Abberline, you...!","TWN":"艾伯林，你……！"},"stage":{"bg":"SWANSONG_04","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래, 이제 더는 미룰 수 없겠지.","JPN":"そう、もうこれ以上は先延ばしできないな。","ENG":"Yes. I can't afford to delay it any longer.","TWN":"嗯，現在不能再拖了。"},"stage":{"bg":"SWANSONG_04","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"스완, 자네에게 전해야 할 말이 있네.","JPN":"スワン、君に話さないといけないことがある。","ENG":"Swan. There is something I should tell you.","TWN":"史旺，我有話要對你說。"},"stage":{"bg":"SWANSONG_04","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"줄곧 전하지 못했던 이 세계의 <color=#ffd34c>진실</color>이지.","JPN":"ずっと伝えられなかった、この世界の<color=#ffd34c>真実</color>だ。","ENG":"It's about the <color=#ffd34c>truth</color> of this world that hasn't been told.","TWN":"一直沒能告訴你的，這個世界的<color=#ffd34c>真相</color>。"},"stage":{"bg":"SWANSONG_04","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이 세계의 진실이라고요……?","JPN":"この世界の真実……？","ENG":"The truth of this world...?","TWN":"這個世界的真相嗎……？"},"stage":{"bg":"SWANSONG_04","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"CITIZEN_SWANSONG_NPC_NULL","text":{"KOREA":"사, 사람들이 하늘로 끌려 올라가고 있어……!","JPN":"ひ、人が空に向かって浮き上がっている……！","ENG":"P-people are being dragged up into the sky...!","TWN":"人，人們被拉上了天空……！"},"stage":{"bg":"MS_1203","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CITIZEN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_MONSTER_THEFOURTH_START"},{"id":"L30_1","type":"dialog","speaker":"CITIZEN_SWANSONG_NPC_NULL","text":{"KOREA":"위를 보지 마! 하늘의 눈과 마주치면 마물이 되어버린다고……!","JPN":"上を見るな！　空と目が合うと魔物になってしまう……！","ENG":"Don't look up! You make eye contact with the eye of the sky and you'll turn into a monster...!","TWN":"不要看上面！一旦與天空對視，就會變成怪物的……！"},"stage":{"bg":"MS_1203","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CITIZEN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CITIZEN_SWANSONG_NPC_NULL","text":{"KOREA":"과, 관절이 뒤틀려서…….","JPN":"か、関節が曲がって……","ENG":"M-my joints are twisting–","TWN":"你、你的關節在扭曲啊啊啊……"},"stage":{"bg":"MS_1203","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CITIZEN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CITIZEN_SWANSONG_NPC_NULL","text":{"KOREA":"으, 으아, 으아아아아아아아아악……!!","JPN":"う、うわ、うわああああああああ……！！","ENG":"A-AAAAAAAAGH...!!","TWN":"呃？呃啊，呃啊啊啊啊啊啊啊啊啊……！！"},"stage":{"bg":"MS_1203","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CITIZEN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L37_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"왕이시여. 당신의 권능이 이 세계의 거의 모든 인간을 절멸시켰습니다.","JPN":"王よ。あなたの権能がこの世界のほぼすべての人間を絶滅させました。","ENG":"My queen. Your power has almost wiped out the entire human population.","TWN":"王，你的權能幾乎滅絕了這個世界上的所有人類。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CITIZEN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"이제 이 세계가 당신의 클리파 차원으로 예속되는 건 시간 문제겠지요.","JPN":"この世界があなたのクリファ次元に隷属されるのは、時間の問題でしょう。","ENG":"Now, it will only be a matter of time before this world is subjugated into your Qlipha Dimension.","TWN":"現在，讓這個世界歸屬於你的逆卡巴拉次元只是時間問題了。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CITIZEN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"아니에요, 언니.","JPN":"違います、お姉ちゃん。","ENG":"No, Sola.","TWN":"不，姊姊。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CITIZEN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"아직 이 세계의 대적자가 누구인지 밝혀내지 못했어요.","JPN":"まだこの世界の敵対者が誰なのか、わかっていません。","ENG":"The Antagonist of this world has not been revealed yet.","TWN":"還沒有查明這個世界的敵對者是誰。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CITIZEN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"대적자는 이 세계의 인간의 수가 줄어들면, 줄어들수록 더욱 위험한 존재가 되니까요.","JPN":"敵対者はこの世界の人間の数が減るほど、より危険な存在になります。","ENG":"The Antagonist will become more dangerous as the number of humans in this world decrease.","TWN":"敵對者會隨著這個世界上人類數量的減少，變得更加危險。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CITIZEN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"제아무리 잔불만이 남아버린 세계라고 할지라도, 철저하게 짓밟는 편이 좋겠죠.","JPN":"小さな火種しか残っていない世界だとしても、徹底的に踏み潰しておいた方がいいでしょう。","ENG":"Even if only an ember is left in this world, it would be best to stomp it out completely.","TWN":"即使這個世界只剩下殘火，也最好徹底碾碎它。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CITIZEN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"하지만 왕이시여.","JPN":"ですが、王よ。","ENG":"But my queen.","TWN":"但是，王上。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CITIZEN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"성자의 힘은 성자 스스로에 대한 인식과 그 세계 인류의 총체적인 인식으로부터 결정됩니다.","JPN":"聖者の力は自分への認識と、その世界の人類の総合的な認識で決定されます。","ENG":"The power of a Helgon is determined from its own awareness and humanity overall.","TWN":"聖者的力量取決於聖者對自身的認知以及那個世界全人類的總體認知。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CITIZEN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"개인이 가진 가능성과 세계 전체가 품고 있는 가능성…….","JPN":"個人の持つ可能性と世界全体が宿している可能性……","ENG":"The possibilities from an individual and the possibilities the world embraces as a whole...","TWN":"個人的潛力和整個世界所蘊含的可能性……"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CITIZEN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"이 두 조건을 만족해야 비로소 강한 성자가 나타날 수 있죠.","JPN":"この二つの条件を満さないと、強い聖者は現われません。","ENG":"A powerful Helgon will emerge only when these two conditions are fulfilled.","TWN":"只有滿足這兩個條件，才能出現強大的聖者。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CITIZEN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"하물며, 성자를 멸시하는 이 세계에서 대적자라 한들, 왕의 상대가 될 리 없습니다.","JPN":"ましてや聖者が軽蔑の対象とされるこの世界の敵対者なら、王の相手など務まるはずがありません。","ENG":"Moreover, an Antagonist from a world that despises Helgons cannot possibly be a match for you.","TWN":"更何況是這個蔑視聖者的世界……即使出現了敵對者，也不足以成為王的對手。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CITIZEN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CITIZEN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"때마침 도착한 모양이로군요. 이 세계의 선택받은 자가.","JPN":"ちょうど着いたようですね。この世界の選ばれし者が。","ENG":"It seems that she has arrived. The one chosen by this world.","TWN":"看來正好趕來了。這個世界的選擇。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"CITIZEN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"저도 언니의 눈을 빌려, 이 세계를 쭉 지켜봐 왔지만 의외네요.","JPN":"私もお姉ちゃんの目を借りて、この世界をずっと見守ってきましたけど、意外ですね。","ENG":"I too have borrowed your vision and have kept an eye on this world, but it is unusual.","TWN":"我也借用了姊姊的眼睛，一直在觀察這個世界，真是出乎意料啊。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"설마, 당신 같은 가녀린 소녀가 이 세계의 선택을 받은 사람일 줄은 몰랐네요.","JPN":"まさか、あなたのようなか弱い少女がこの世界に選ばれし人だとは。","ENG":"Who would've thought that a frail girl like you would be the chosen one.","TWN":"沒想到，像你這樣纖弱的少女竟然是被這個世界選中的人。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"스완 클레어라고 했나요?","JPN":"スワン・クレアでしたね。","ENG":"Swan Claire, was it?","TWN":"你是叫史旺·克萊爾嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"누가 봐도 그 잘난 탐정이 대적자의 운명을 타고난 자가 아닐까 싶었는데 말이죠.","JPN":"誰が見てもあの探偵が敵対者の運命を持つ者だと思っていたのですが。","ENG":"I was almost certain that the detective would be the one destined with the Antagonist's fate.","TWN":"誰看了都會覺得那個自命不凡的偵探才是天生的敵對者吧。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그렇군요. 당신이 이 세계를 침공한 마왕…….","JPN":"そうですね。あなたがこの世界を侵攻した魔王……","ENG":"I see. So, you are the Demon Lord who has invaded this world...","TWN":"原來如此。你就是入侵這個世界的魔王……"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"제가 이 세계의 대적자라는 걸 알고 계시니, 이야기가 빠르겠군요.","JPN":"私がこの世界の敵対者だということをご存じなら、話が早いでしょう。","ENG":"Since you already know that I'm this world's Antagonist, it makes this easier for me.","TWN":"既然你知道我是這個世界的敵對者，那事情就簡單了。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"탐정은 죽었습니다.","JPN":"探偵は死にました。","ENG":"The detective is dead.","TWN":"偵探死了。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 저는 이 자리에 싸우러 온 게 아니에요.","JPN":"そして、私は戦うためにこの場に来たわけではありません。","ENG":"And I am not here to fight.","TWN":"而我不是來這裡打架的。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"아니, 오히려 반대죠.","JPN":"いや、むしろその逆です。","ENG":"It's actually the opposite.","TWN":"不，恰恰相反。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"배우로서 당신과 전속 계약을 맺으러 왔습니다. 마왕이여.","JPN":"俳優として、あなたと専属契約をするために参りました。魔王。","ENG":"I have come here to create an exclusive contract with you as an actress, Demon Lord.","TWN":"作為演員，我是來和你簽訂專屬契約的。魔王大人。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};